sql:
SELECT * 
FROM concepts 
ORDER BY number ASC;

SELECT english
FROM concepts
WHERE id = '0';

SELECT AVG(num_translations) AS avg_translations_per_concept
FROM (
    SELECT concept_id, COUNT(translation_id) AS num_translations
    FROM translations
    GROUP BY concept_id
);

SELECT DISTINCT u.username, u.email, u.role
FROM users u
INNER JOIN concepts c ON u.username = c.updated_by;

SELECT c.english, c.concept_type, u.username
FROM concepts c
JOIN users u ON c.created_by = u.username;
